var b="url",c="直接出库__231031_.html",d="generationDate",e=new Date(1781494401535.48),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="a4ea75174e6c42acad73fe04e3119e9f",v="type",w="Axure:Page",x="直接出库 (231031)",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="4e5a2090eaf844a39fe8ee4f2aa8c3bf",E="label",F="开始出库",G="说明",H="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的字符串是否为系统内生成过的“唯一码”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.生成过：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.未生成：返回Toast提示‘未生成的物料唯一码’；停留在当前列表页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.校验“唯一码”的实际库存是否大于0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.实际库存＞0：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.实际库存≤0：Toast提示‘无库存的唯一码’；停留在当前列表页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验，将识别的'唯一码'及相关参数传至[出库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.若“唯一码”已存在于本次出库的[出库明细]中，将已填写的出库信息(出库数量)传至[出库信息页]后支持修改</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若“唯一码”未存在于本次出库的[出库明细]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.将识别出的'唯一码'及唯一码对应的物料信息(物料名称、编码、颜色、规格、缸号、卷号、批次号、备注)至[出库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库：初始化等于查询出的'库存' （</span><span>该唯一码对应的'可用库存'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">）</span></p>",I="2",J="90fd4b9cc410437faff9c80d40d0aa0b",K="物料：",L="<p><span>1.展示方式为 '</span><span style=\"color:#02A7F0;\">物料名称</span><span>'+'</span><span style=\"color:#02A7F0;\">(</span><span>'+'</span><span style=\"color:#02A7F0;\">物料编码</span><span>'+'</span><span style=\"color:#02A7F0;\">)</span><span>'</span></p><p><span>2.若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p>",M="3",N="6956a2a94e5a4f1b99939b398f370a25",O="颜色：",P="<p><span>1.若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p>",Q="4",R="6f5bb39f103b4af4854ed796c2ae0a45",S="库存：",T="<p><span>指该唯一码对应的'可用库存'</span></p>",U="5",V="06e489084bf042fd8493cdf624e07950",W="* 出库：",X="<p><span>1.默认值：取‘库存’</span></p><p><span>2.格式：保留两位小数</span></p><p><span>3.限制数值不能大于'库存'</span></p>",Y="6",Z="abd6a067a59f467db94dbaf9dafcf6d4",ba="继续扫码",bb="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">校验当前“出库”编辑域</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.校验“出库”是否大于0</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库＞ 0：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库 ≤ 0：Toast提示‘请输入出库数量’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.校验“出库”是否超出库存</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库 ≤ 库存：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库＞库存：Toast提示‘出库数量不得大于当前库存’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.将当前“唯一码”所属的物料SKU新增/修改至[出库列表]中</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">未存在的SKU：使其它卡片下移，增加当前SKU至顶部；计算后记录</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库标签</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">和</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">存在的SKU：存在的SKU：即时更新该所属的SKU的汇总</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库标签</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">及</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库数量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.将当前“唯一码”中填写的出库信息新增/修改至[出库列表：物料明细]中</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">新增：新增至对应SKU出库明细内清单最底部</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">修改：在原出库明细内清单位置不变，刷新对应的唯一码出库数量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.返回Toast提示&quot;操作成功&quot;；将当前所有字段</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">清空</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">(唯一码信息及出库数量)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">再次调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">调用摄像头，进行扫码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验识别的字符串是否为系统内生成过的“唯一码”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.生成过：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.未生成：返回Toast提示‘未生成的物料唯一码’；停留在当前出库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.校验“唯一码”的实际库存是否大于0</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.实际库存＞0：通过校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.实际库存≤0：Toast提示‘无库存的唯一码’；停留在当前出库信息页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">通过校验，将识别的'唯一码'及相关参数传至当前[出库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.若“唯一码”已存在于本次出库的[出库明细]中，将已填写的出库信息(出库数量)传至[出库信息页]后支持修改</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若“唯一码”未存在于本次出库的[出库明细]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.将识别出的'唯一码'及唯一码对应的物料信息(物料名称、编码、颜色、规格、缸号、卷号、批次号、备注)至[出库信息页]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.数量：初始化等于查询出的'库存' （</span><span>该唯一码对应的'可用库存'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">）</span></p>",bc="7",bd="c1ee7f38080d49d49f4ccbd7ab01b05d",be="结束扫码",bf="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">当前'唯一码'为空</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">返回页面至[出库列表]页</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">当前'唯一码'不为空</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.校验“出库”是否大于0</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库＞ 0：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库 ≤ 0：Toast提示‘请输入出库数量’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.校验“出库”是否超出库存</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库 ≤ 库存：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库＞库存：Toast提示‘出库数量不得大于当前库存’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">3.通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"color:#333333;\">将当前“唯一码”所属的物料SKU新增/修改至[出库列表]中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.未存在的SKU：使其它卡片下移，增加当前SKU至顶部；计算后记录</span><span style=\"text-decoration:underline ;color:#333333;\">出库标签</span><span style=\"color:#333333;\">和</span><span style=\"text-decoration:underline ;color:#333333;\">出库数量</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.存在的SKU：存在的SKU：即时更新该所属的SKU的汇总</span><span style=\"text-decoration:underline ;color:#333333;\">出库标签</span><span style=\"color:#333333;\">及</span><span style=\"text-decoration:underline ;color:#333333;\">出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"color:#333333;\">将当前“唯一码”中填写的出库信息新增/修改至[出库列表：物料明细]中</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.新增：新增至对应SKU出库明细内清单最底部</span></p><p><span style=\"color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.修改：在原出库明细内清单位置不变，刷新对应的唯一码出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; c.</span><span style=\"color:#333333;\">返回Toast提示&quot;操作成功&quot;并返回页面至[出库列表]页</span></p>",bg="8",bh="56f6780441e241e9995ce5c84708e0dd",bi="清空数据",bj="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">弹窗</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">确认是否清除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.二次确认后移除</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">当前账户在[直接出库]下缓存的“出库明细”数据</span></p>",bk="9",bl="4356de7716434dfdbd20bf84e7e235f5",bm="(矩形)",bn="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">卡片描述</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.物料编码：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">展示全</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，一般字符串长度不会超限；若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.物料名称：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示单行宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.颜色、规格：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示固定宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示；颜色和规格在单行中均占50%的宽度</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.出库标签/数量：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.1 使用' / '将出库标签数量与出库数量进行分隔</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.2 出库标签：其SKU下'唯一码'的个数</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 4.3 出库数量：其SKU下'唯一码'的出库数量的汇总；使用红色字体标识</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">5.【点击】跳转至SKU对应[出库明细]页展示其“唯一码’相关信息</span></p>",bo="10",bp="04f3e232065a4dd98a2d987df98e2933",bq="扫描物料",br="11",bs="19e7badb73c848fa8f16383023e5f692",bt="确认出库",bu="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验当前的出库明细中是否包含唯一码填写的“出库数量”超过当前实际的“可用库存”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 1.1 不包含：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">弹窗</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">确认出库信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 1.1.1 二次确认最终按逻辑生成出库单</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 1.2 包含：将“出库数量”超过当前实际的“可用库存”的唯一码信息展示于</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">跳转页面[库存不足]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">页面</span></p>",bv="12",bw="6b0e59f3d0e64898a89f49d79bcfa341",bx="剩余库存",by="<p><span>“唯一码”在库存中的“可用库存”</span></p>",bz="13",bA="a2906b8144a84fea9f539f04a0b92ce1",bB="确认移除",bC="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.清除当前用户下，直接出库明细中上述唯一码的缓存数据</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.返回至[出库列表]页</span></p>",bD="14",bE="61dce97b18f6416e87874ad656b9f189",bF="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.按照'唯一码'来源当前在库存所属“仓库”分开生成出库单(CKD)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.唯一码共计跨了几个仓库就生成几个出库单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.出库类型均为'直接出库'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c.出库单的单据状态跟随系统审批流配置；并且记录当前操作人和操作时间至创建/更新人及时间</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d.出库物料明细</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.原唯一码库存在哪个仓库，就将其记录在对应仓库的出库单内</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; e.出库物料汇总</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.数量为出库物料明细的SKU汇总成的出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.“出库单价”使用[仓库配置&gt;&gt;小程序默认单价&gt;&gt;直接出库]选中的计算方式</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.“备注”：将当前缓存的相同SKU下唯一码出库明细中填写的'备注'使用逗号拼接(仅对有值的拼接)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; f.对库存进行变更</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.Toast提示：操作成功</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.跳转至'菜单页'</span></p>",bG="15",bH="06cd250feb8743ba801218219451848d",bI="确认",bJ="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">清空当前账户在[直接出库]下缓存的“出库明细”数据</span></p>",bK="16",bL="d11b77774126467c83f353fa8a3c92df",bM="17",bN="2f404f1aff944628bdc7caeaca1636af",bO="唯一码",bP="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">点击将对应'唯一码'及相关参数传至[出库信息编辑页]，用以编辑唯一码的出库信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">将“唯一码”上已填写的出库信息(全部字段)传至[出库信息编辑页]后支持修改</span></p>",bQ="18",bR="3e2ad48fd307449396c29946422d3523",bS="(单元格)",bT="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.直接将对应行唯一码移除，返回Toast提示：移除成功</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.若已是明细中最后一个唯一码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; a.将这个SKU卡片从出库清单页移除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">页面返回至[出库列表]页</span></p>",bU="19",bV="036048165771431b951455083da67f37",bW="确认修改",bX="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">1.校验“出库”是否大于0</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库＞ 0：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库 ≤ 0：Toast提示‘请输入出库数量’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">2.校验“出库”是否超出库存</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; a.出库 ≤ 库存：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; b.出库＞库存：Toast提示‘出库数量不得大于当前库存’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">3.将当前出库信息上填写值覆盖至当前'唯一码'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">4.返回Toast提示：编辑成功</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">5.返回[出库明细]页</span></p>",bY="20",bZ="3f4d72a6f030451488afec93e367f3b8",ca="提示",cb="<p><span>出库种类：列表SKU的数量</span></p><p><span>出库标签：Σ出库标签</span></p><p><span>出库数量：Σ出库数量</span></p>",cc="21",cd="a4188be529364af1bcc464964e9a3ca6",ce="确定",cf="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.按照'唯一码'来源当前在库存所属“仓库”分开生成出库单(CKD)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.唯一码共计跨了几个仓库就生成几个出库单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.出库类型均为'直接出库'</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c.出库单的单据状态跟随系统审批流配置；并且记录当前操作人和操作时间至创建/更新人及时间</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d.出库物料明细</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.原唯一码库存在哪个仓库，就将其记录在对应仓库的出库单内</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.出库信息填写的“备注”对应至唯一码的相关的“出库备注”中</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; e.出库物料汇总</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.数量为出库物料明细的SKU汇总成的出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.“出库单价”使用[仓库配置&gt;&gt;小程序默认单价&gt;&gt;直接出库]选中的计算方式</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; f.对库存进行变更</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.Toast提示：操作成功</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.跳转至'菜单页'</span></p>",cg="22",ch="5ddacd999eb34dd9b5e9e26ee3ec43fa",ci="(手机)",cj="<p><span>【暂未开发】</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">页面描述：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.初始无数据展示，仅通过'物料编码'或‘物料名称’点击的模糊搜索后检索清单出数据</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.数据源：对[物料库存-库存明细]中的唯一码，以'仓库-物料编码-规格/门幅-颜色'为单位进行汇总</span></p>",ck="23",cl="8a3b4298f018428c909a32e08aa91b27",cm="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">卡片描述：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.物料编码：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">展示全</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，一般字符串长度不会超限；若超出单行宽度时换行展示，注意换行开始的位置是展示字段不是从标题开始</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.物料名称：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示单行宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.颜色、规格：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示固定宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；如原型图所示；颜色和规格在单行中均占50%的宽度</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.仓库：展示方式为 '</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">仓库名称</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">'+'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">(</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">'+'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">库位编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">'+'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">)</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">'；</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">仅展示固定宽度的字符</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，多余部分使用'…'进行补足；</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">5.库存：取汇总部分下唯一码的Σ&quot;可用库存&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">6.推荐：展示全部该'仓库-SKU'的唯一码所属的具体库位</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 6.1 展示的库位编码不需要展示'仓库编码-'部分的值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 6.2 查到的库位注意进行去重，使用逗号拼接</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; 6.3 排序：以库位上的合计唯一码可用库存数量从大到小排(后续将使用配置项排序)</span></p>",cn="24",co="e47b11e091704ff8b214dbba89d2eea1",cp="<p><span>1.清单数据源：[订单管理&gt;&gt;生产订单]中所有状态为&quot;已通过&quot;的生产订单</span></p><p><span>2.卡片-订单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.取值：生产单号(自定义单号)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.若自定义单号为空，不展示对应的()</span></p><p><span>3.卡片-款式</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.取值：款号(款名)</span></p><p><span>4.选中卡片后，将其“生产单号(自定义单号)”返回至列表页</span></p>",cq="25",cr="d0103f4ea78c45b4967bbbb774ea52ab",cs="关闭",ct="<p><span>关闭筛选面板</span></p>",cu="style",cv="baseStyle",cw="627587b6038d43cca051c114ac41ad32",cx="pageAlignment",cy="center",cz="fill",cA="fillType",cB="solid",cC="color",cD=0xFFFFFFFF,cE="image",cF="imageAlignment",cG="near",cH="imageRepeat",cI="auto",cJ="favicon",cK="sketchFactor",cL="0",cM="colorStyle",cN="appliedColor",cO="fontName",cP="Applied Font",cQ="borderWidth",cR="borderVisibility",cS="borderFill",cT=0xFF797979,cU="cornerRadius",cV="cornerVisibility",cW="outerShadow",cX="on",cY=false,cZ="offsetX",da=5,db="offsetY",dc="blurRadius",dd="spread",de="r",df=0,dg="g",dh="b",di="a",dj=0.349019607843137,dk="adaptiveStyles",dl="interactionMap",dm="diagram",dn="objects",dp="id",dq="f4911a0ab42745e89c36abb6edd43feb",dr="friendlyType",ds="手机",dt="referenceDiagramObject",du="styleType",dv="visible",dw=true,dx=450,dy=800,dz="location",dA="x",dB=1200,dC="y",dD="imageOverrides",dE="masterId",dF="4fac3643f4954cc4b8de2be8db632c44",dG="5c5bdc78899c414d8798f3e0a062ce36",dH=1730,dI="d33cc6d3f8c344458ffb107eabbe38cf",dJ="调整物料明细",dK="表格",dL="table",dM=410,dN=120,dO=1750,dP=265,dQ="58b6ebdeb53b4760bc757d4a042aab2e",dR="单元格",dS="tableCell",dT="fontWeight",dU="700",dV=60,dW=30,dX="2b919df770544924b45cd529b520fb2f",dY="fontSize",dZ="12px",ea=0xFFD7D7D7,eb=310,ec="horizontalAlignment",ed="left",ee="images",ef="normal~",eg="images/直接入库__240704_/u7128.png",eh="28f7aaf0a51d4156a65b8d514be37c0d",ei="2f404f1aff944628bdc7caeaca1636af",ej=110,ek="images/直接入库__240704_/u7125.png",el="829c290aba6344cfa79b4c67b35fd63e",em="foreGroundFill",en=0xFF70B603,eo="opacity",ep=1,eq="9adda6e5f58e424e991657a5d6d0919a",er="66b9a8500da3471582565295b44895de"